scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		if (x_snc_devtools.IsDerivedFromTable(current.name,'task') == true)
		{
			var grDictOverride = x_snc_devtools.GetDictionaryOverrideRecord(current.name,'number');
			if (x_snc_devtools.IsValidRecord(grDictOverride) == false)
			{
				engine.finding.increment();
				return;	
			}

			if (
				grDictOverride.read_only_override == false
				|| grDictOverride.read_only == false
				|| grDictOverride.base_table != 'task')
			{
				engine.finding.increment();
				return;
			}
		}
	}

})(engine);
